const ALIASES = {
  afyonkarahisar: "Afyon",
  kiriklareli: "Kırklareli",
  icel: "Mersin",
  kmaras: "Kahramanmaraş",
  kahramanmaras: "Kahramanmaraş",
  sanliurfa: "Şanlıurfa",
  urfa: "Şanlıurfa",
};

function normKey(s) {
  if (!s) return "";
  let x = String(s).trim();
  const map = { İ: "i", I: "i", ı: "i", Ş: "s", ş: "s", Ğ: "g", ğ: "g", Ü: "u", ü: "u", Ö: "o", ö: "o", Ç: "c", ç: "c", Â: "a", â: "a" };
  x = x.replace(/[İIıŞşĞğÜüÖöÇçÂâ]/g, (ch) => map[ch] || ch).toLowerCase();
  x = x.replace(/[^a-z0-9]/g, "");
  return x;
}

function colorFor(count, max) {
  if (!count) return "#eef2f0";
  const t = Math.min(1, Math.log(count + 1) / Math.log(max + 1));
  const c1 = [167, 243, 208];
  const c2 = [15, 118, 110];
  const r = Math.round(c1[0] + (c2[0] - c1[0]) * t);
  const g = Math.round(c1[1] + (c2[1] - c1[1]) * t);
  const b = Math.round(c1[2] + (c2[2] - c1[2]) * t);
  return "rgb(" + r + "," + g + "," + b + ")";
}

// Tamamen büyük harfli firma isimlerini okunaklı hale getirir (ör. "ZORLU
// DEĞİRMEN" → "Zorlu Değirmen"). Zaten düzgün yazılmış isimlere dokunmaz.
const _trLower = (s) => s.replace(/[İI]/g, (c) => ({ İ: "i", I: "ı" }[c])).toLocaleLowerCase("tr-TR");
const _trUpper = (s) => s.replace(/[iı]/g, (c) => ({ i: "İ", ı: "I" }[c])).toLocaleUpperCase("tr-TR");
const toTitleCaseTR = (name) => {
  if (!name) return name;
  const letters = name.replace(/[^A-Za-zÇĞİIÖŞÜçğıiöşü]/g, "");
  if (!letters || letters !== _trUpper(letters)) return name;
  return name
    .split(" ")
    .map((w) => {
      if (!w) return w;
      if (w.includes(".")) return w;
      const lower = _trLower(w);
      if (lower === "ve" || lower === "ile") return lower;
      return lower.split("-").map((s) => (s ? _trUpper(s[0]) + s.slice(1) : s)).join("-");
    })
    .join(" ");
};

const MARKET_COLORS = ["#0d9488", "#3b82f6", "#f59e0b", "#ef4444", "#8b5cf6", "#ec4899", "#14b8a6", "#64748b"];

// Sistemdeki sabit durum değerleri (içe aktarma şablonuyla birebir aynı).
const STATUS_OPTIONS = ["Beklemede", "İletişimde", "Çalışılıyor", "Takip Ediliyor", "Olumsuz", "Kapandı"];

export default function TurkeyMap() {
  const navigate = useNavigate();
  const { openCustomerModal } = useCustomerModal();
  const [counts, setCounts] = useState({});
  const [loading, setLoading] = useState(true);
  const [hover, setHover] = useState(null);

  // Filtre çubuğu — Müşteriler sayfasındakiyle aynı mantık: market, durum,
  // uygulama, rakip, partner. Seçilince harita ve alttaki pop-up'lar otomatik
  // olarak sadece o filtreye uyan müşterileri yansıtır.
  const [filters, setFilters] = useState({ market: "", application: "", status: "", competitor: "", partner: "" });
  const [filterOptions, setFilterOptions] = useState({ market: [], application: [], competitor: [], partner: [] });

  // Pop-up durumu
  const [selectedCity, setSelectedCity] = useState(null);
  const [markets, setMarkets] = useState([]); // [{market, count}]
  const [cityTotal, setCityTotal] = useState(0);
  const [marketsLoading, setMarketsLoading] = useState(false);
  const [activeMarket, setActiveMarket] = useState(null); // seçili market ("__ALL__" = tümü)
  const [customers, setCustomers] = useState([]);
  const [custLoading, setCustLoading] = useState(false);
  const [fullscreen, setFullscreen] = useState(false);

  // Filtre seçeneklerini (mevcut market/uygulama/rakip/partner değerleri) bir
  // kez çek — Müşteriler sayfasının kullandığı aynı endpoint, 60sn cache'li.
  useEffect(() => {
    let alive = true;
    (async () => {
      try {
        const { data } = await axios.get(`${API}/customers/filter-options`);
        if (!alive) return;
        setFilterOptions({
          market: data.market || [],
          application: data.application || [],
          competitor: data.competitor || [],
          partner: data.partner || [],
        });
      } catch (err) {
        console.error("Filtre seçenekleri alınamadı:", err);
      }
    })();
    return () => { alive = false; };
  }, []);

  const buildFilterQS = useCallback((f) => {
    const p = new URLSearchParams();
    Object.entries(f).forEach(([k, v]) => { if (v) p.set(k, v); });
    return p.toString();
  }, []);

  const activeFilterCount = useMemo(() => Object.values(filters).filter(Boolean).length, [filters]);
  const updateFilter = useCallback((key, value) => setFilters((f) => ({ ...f, [key]: value })), []);
  const clearFilters = useCallback(() => setFilters({ market: "", application: "", status: "", competitor: "", partner: "" }), []);

  // Harita verisi — aktif filtrelere göre yeniden çekilir (dinamik renklendirme).
  useEffect(() => {
    let alive = true;
    (async () => {
      try {
        setLoading(true);
        const qs = buildFilterQS(filters);
        const { data } = await axios.get(`${API}/stats/distribution?field=city&limit=50${qs ? "&" + qs : ""}`);
        if (!alive) return;
        const byKey = {};
        PROVINCES.forEach((p) => { byKey[normKey(p.n)] = p.n; });
        const out = {};
        (data.entries || []).forEach((e) => {
          const raw = e._id || "";
          const key = normKey(ALIASES[normKey(raw)] || raw);
          const prov = byKey[key];
          if (prov) out[prov] = (out[prov] || 0) + e.count;
        });
        setCounts(out);
      } catch (err) {
        console.error("Harita verisi alınamadı:", err);
      } finally {
        if (alive) setLoading(false);
      }
    })();
    return () => { alive = false; };
  }, [filters, buildFilterQS]);

  const max = useMemo(() => Math.max(1, ...Object.values(counts)), [counts]);
  const total = useMemo(() => Object.values(counts).reduce((a, b) => a + b, 0), [counts]);
  const topCities = useMemo(
    () => Object.entries(counts).sort((a, b) => b[1] - a[1]).slice(0, 5),
    [counts]
  );

  // İle tıkla → pop-up aç, market dağılımını çek (aktif filtrelerle birlikte)
  const openCity = useCallback(async (name) => {
    setSelectedCity(name);
    setActiveMarket(null);
    setCustomers([]);
    setMarkets([]);
    setMarketsLoading(true);
    try {
      const qs = buildFilterQS(filters);
      const { data } = await axios.get(`${API}/stats/city-markets?city=${encodeURIComponent(name)}${qs ? "&" + qs : ""}`);
      setMarkets(data.entries || []);
      setCityTotal(data.total || 0);
    } catch (err) {
      console.error("İl market dağılımı alınamadı:", err);
    } finally {
      setMarketsLoading(false);
    }
  }, [filters, buildFilterQS]);

  // Market seç → o müşterileri listele ("__ALL__" = tümü). Global filtre
  // olarak bir market seçiliyse (üstteki filtre çubuğundan) o zaten tüm
  // dağılıma yansımıştır; burada sadece pop-up içindeki yerel seçim +
  // diğer aktif filtreler (durum, uygulama, rakip, partner) birlikte uygulanır.
  const selectMarket = useCallback(async (marketSel) => {
    if (!selectedCity) return;
    setActiveMarket(marketSel);
    setCustLoading(true);
    try {
      const effectiveMarket = marketSel !== "__ALL__" ? marketSel : (filters.market || "");
      let url = `${API}/customers?city=${encodeURIComponent(selectedCity)}&limit=200&sort_by=company_name&sort_order=asc`;
      if (effectiveMarket) url += `&market=${encodeURIComponent(effectiveMarket)}`;
      const { market: _omitMarket, ...otherFilters } = filters;
      const qs = buildFilterQS(otherFilters);
      if (qs) url += `&${qs}`;
      const { data } = await axios.get(url);
      setCustomers(data.data || data.items || []);
    } catch (err) {
      console.error("Müşteri listesi alınamadı:", err);
      setCustomers([]);
    } finally {
      setCustLoading(false);
    }
  }, [selectedCity, filters, buildFilterQS]);

  const closeModal = () => {
    setSelectedCity(null);
    setFullscreen(false);
  };

  // "Müşterilerde Aç" — il + market + üstteki tüm aktif filtreleri URL'e
  // taşır; Customers.jsx artık bu parametreleri sayfa açılışında okuyor.
  const openInCustomers = () => {
    const effectiveMarket = activeMarket && activeMarket !== "__ALL__" ? activeMarket : (filters.market || "");
    const p = new URLSearchParams();
    p.set("city", selectedCity);
    if (effectiveMarket) p.set("market", effectiveMarket);
    if (filters.application) p.set("application", filters.application);
    if (filters.status) p.set("status", filters.status);
    if (filters.competitor) p.set("competitor", filters.competitor);
    if (filters.partner) p.set("partner", filters.partner);
    closeModal();
    navigate(`/customers?${p.toString()}`);
  };

  return (
    <div className="glass-card p-4 h-full flex flex-col">
      <div className="flex items-center justify-between mb-2">
        <div className="flex items-center gap-2">
          <MapPin className="w-4 h-4 text-tertiary-md" />
          <h3 className="font-semibold text-foreground text-sm">Türkiye Müşteri Yoğunluğu</h3>
        </div>
        <span className="text-xs text-muted-foreground">
          {total} müşteri{activeFilterCount > 0 ? " (filtrelenmiş)" : ""}
        </span>
      </div>

      {/* Filtre çubuğu — seçim yapınca harita ve popup'lar otomatik güncellenir */}
      <div className="flex flex-wrap items-center gap-1.5 mb-3 pb-3 border-b border-border/60">
        <div className="flex items-center gap-1 text-xs text-muted-foreground mr-0.5">
          <Filter className="w-3.5 h-3.5" />
        </div>
        <select
          value={filters.market}
          onChange={(e) => updateFilter("market", e.target.value)}
          className="text-xs border border-border rounded-md px-2 py-1 bg-background text-foreground max-w-[130px]"
        >
          <option value="">Market (Tümü)</option>
          {filterOptions.market.map((v) => (
            <option key={v} value={v}>{v}</option>
          ))}
        </select>
        <select
          value={filters.status}
          onChange={(e) => updateFilter("status", e.target.value)}
          className="text-xs border border-border rounded-md px-2 py-1 bg-background text-foreground max-w-[130px]"
        >
          <option value="">Durum (Tümü)</option>
          {STATUS_OPTIONS.map((v) => (
            <option key={v} value={v}>{v}</option>
          ))}
        </select>
        <select
          value={filters.application}
          onChange={(e) => updateFilter("application", e.target.value)}
          className="text-xs border border-border rounded-md px-2 py-1 bg-background text-foreground max-w-[130px]"
        >
          <option value="">Uygulama (Tümü)</option>
          {filterOptions.application.map((v) => (
            <option key={v} value={v}>{v}</option>
          ))}
        </select>
        <select
          value={filters.competitor}
          onChange={(e) => updateFilter("competitor", e.target.value)}
          className="text-xs border border-border rounded-md px-2 py-1 bg-background text-foreground max-w-[130px]"
        >
          <option value="">Rakip (Tümü)</option>
          {filterOptions.competitor.map((v) => (
            <option key={v} value={v}>{v}</option>
          ))}
        </select>
        <select
          value={filters.partner}
          onChange={(e) => updateFilter("partner", e.target.value)}
          className="text-xs border border-border rounded-md px-2 py-1 bg-background text-foreground max-w-[130px]"
        >
          <option value="">Partner (Tümü)</option>
          {filterOptions.partner.map((v) => (
            <option key={v} value={v}>{v}</option>
          ))}
        </select>
        {activeFilterCount > 0 && (
          <button
            onClick={clearFilters}
            className="flex items-center gap-1 text-xs px-2 py-1 rounded-md bg-red-50 text-red-600 hover:bg-red-100 transition-colors"
          >
            <X className="w-3 h-3" /> Temizle ({activeFilterCount})
          </button>
        )}
      </div>

      <div className="relative flex-1 min-h-[260px]">
        {loading && (
          <div className="absolute inset-0 flex items-center justify-center text-muted-foreground">
            <Loader2 className="w-5 h-5 animate-spin mr-2" /> Harita yükleniyor...
          </div>
        )}
        <svg viewBox={VIEWBOX} className="w-full h-full" style={{ maxHeight: 340 }} onMouseLeave={() => setHover(null)}>
          {PROVINCES.map((p) => {
            const cnt = counts[p.n] || 0;
            const active = hover && hover.name === p.n;
            return (
              <path
                key={p.c}
                d={p.d}
                fill={colorFor(cnt, max)}
                stroke={active ? "#0f766e" : "#ffffff"}
                strokeWidth={active ? 1.4 : 0.6}
                style={{ cursor: "pointer", transition: "fill .15s" }}
                onMouseEnter={(e) => {
                  const svg = e.currentTarget.ownerSVGElement;
                  const r = svg.getBoundingClientRect();
                  const b = e.currentTarget.getBBox();
                  setHover({ name: p.n, count: cnt, x: ((b.x + b.width / 2) / 1000) * r.width, y: (b.y / VB_H) * r.height });
                }}
                onClick={() => openCity(p.n)}
              />
            );
          })}
        </svg>

        {hover && (
          <div
            className="absolute pointer-events-none z-10 px-2 py-1 rounded-md bg-slate-800 text-white text-xs shadow-lg"
            style={{ left: hover.x, top: hover.y - 8, transform: "translate(-50%, -100%)", whiteSpace: "nowrap" }}
          >
            <span className="font-medium">{hover.name}</span>: {hover.count} müşteri
          </div>
        )}
      </div>

      <div className="mt-2 flex items-center justify-between gap-2 flex-wrap">
        <div className="flex flex-wrap gap-1">
          {topCities.map(([name, cnt]) => (
            <button
              key={name}
              onClick={() => openCity(name)}
              className="text-[11px] px-2 py-0.5 rounded-full bg-tertiary-fixed/50 text-tertiary-md hover:bg-tertiary-fixed transition-colors"
            >
              {name} ({cnt})
            </button>
          ))}
        </div>
        <div className="flex items-center gap-1 text-[10px] text-muted-foreground">
          <span>Az</span>
          <span className="inline-block w-16 h-2 rounded-full" style={{ background: "linear-gradient(90deg,#a7f3d0,#0f766e)" }} />
          <span>Çok</span>
        </div>
      </div>

      {/* ===== POP-UP ===== */}
      {selectedCity && (
        <div
          className="fixed inset-0 z-50 flex items-center justify-center bg-black/40 backdrop-blur-sm p-4"
          onClick={closeModal}
        >
          <div
            className={`bg-card rounded-2xl shadow-2xl flex flex-col overflow-hidden ${
              fullscreen ? "w-full h-full" : "w-full max-w-2xl max-h-[80vh]"
            }`}
            onClick={(e) => e.stopPropagation()}
          >
            {/* Başlık */}
            <div className="flex items-center justify-between px-4 py-3 border-b bg-muted/40">
              <div className="flex items-center gap-2">
                <MapPin className="w-4 h-4 text-tertiary-md" />
                <h3 className="font-semibold text-foreground">{selectedCity}</h3>
                <span className="text-sm text-muted-foreground">· {cityTotal} müşteri</span>
              </div>
              <div className="flex items-center gap-1">
                <button
                  onClick={openInCustomers}
                  className="flex items-center gap-1 text-xs px-2 py-1 rounded-md bg-primary text-primary-foreground hover:opacity-90"
                  title="Müşteriler sayfasında aç"
                >
                  <ExternalLink className="w-3.5 h-3.5" /> Müşterilerde Aç
                </button>
                <button onClick={() => setFullscreen((f) => !f)} className="p-1.5 rounded-md hover:bg-muted" title={fullscreen ? "Küçült" : "Tam ekran"}>
                  {fullscreen ? <Minimize2 className="w-4 h-4" /> : <Maximize2 className="w-4 h-4" />}
                </button>
                <button onClick={closeModal} className="p-1.5 rounded-md hover:bg-muted" title="Kapat">
                  <X className="w-4 h-4" />
                </button>
              </div>
            </div>

            {/* Market dağılımı */}
            <div className="px-4 py-3 border-b">
              <p className="text-xs text-muted-foreground mb-2">Market dağılımı — bir markete tıklayın</p>
              {marketsLoading ? (
                <div className="flex items-center text-muted-foreground text-sm py-2">
                  <Loader2 className="w-4 h-4 animate-spin mr-2" /> Yükleniyor...
                </div>
              ) : (
                <div className="flex flex-wrap gap-2">
                  <button
                    onClick={() => selectMarket("__ALL__")}
                    className={`text-xs px-2.5 py-1 rounded-full border transition-colors ${
                      activeMarket === "__ALL__" ? "bg-primary text-primary-foreground border-primary" : "bg-muted hover:bg-slate-200 border-transparent"
                    }`}
                  >
                    Tümü ({cityTotal})
                  </button>
                  {markets.map((m, i) => (
                    <button
                      key={m.market}
                      onClick={() => selectMarket(m.market)}
                      className={`text-xs px-2.5 py-1 rounded-full border transition-colors ${
                        activeMarket === m.market ? "text-white border-transparent" : "bg-muted hover:bg-slate-200 border-transparent text-foreground"
                      }`}
                      style={activeMarket === m.market ? { backgroundColor: MARKET_COLORS[i % MARKET_COLORS.length] } : {}}
                    >
                      <span
                        className="inline-block w-2 h-2 rounded-full mr-1 align-middle"
                        style={{ backgroundColor: MARKET_COLORS[i % MARKET_COLORS.length] }}
                      />
                      {m.market} ({m.count})
                    </button>
                  ))}
                </div>
              )}
            </div>

            {/* Müşteri listesi */}
            <div className="flex-1 overflow-y-auto px-4 py-2">
              {!activeMarket && (
                <div className="text-center text-muted-foreground text-sm py-10">
                  <Building2 className="w-8 h-8 mx-auto mb-2 opacity-40" />
                  Müşterileri görmek için yukarıdan bir market seçin
                </div>
              )}
              {activeMarket && custLoading && (
                <div className="flex items-center justify-center text-muted-foreground py-10">
                  <Loader2 className="w-5 h-5 animate-spin mr-2" /> Müşteriler yükleniyor...
                </div>
              )}
              {activeMarket && !custLoading && customers.length === 0 && (
                <div className="text-center text-muted-foreground text-sm py-10">Bu seçimde müşteri yok</div>
              )}
              {activeMarket && !custLoading && customers.length > 0 && (
                <div className="divide-y">
                  {customers.map((c) => (
                    <button
                      key={c.id}
                      onClick={() => { closeModal(); openCustomerModal(c.id); }}
                      className="w-full text-left flex items-center gap-3 py-2 hover:bg-muted/50 rounded-lg px-2 transition-colors"
                    >
                      <div className="w-8 h-8 bg-blue-500 rounded flex items-center justify-center text-white font-semibold text-xs flex-shrink-0">
                        {toTitleCaseTR(c.company_name)?.charAt(0) || "?"}
                      </div>
                      <div className="flex-1 min-w-0">
                        <div className="flex items-center gap-1.5">
                          <span className="font-medium text-sm text-foreground truncate">{toTitleCaseTR(c.company_name)}</span>
                          {c.is_followup && <Bell className="w-3 h-3 text-amber-500 flex-shrink-0" />}
                        </div>
                        <div className="text-xs text-muted-foreground truncate">
                          {[c.district, c.application, c.status].filter(Boolean).join(" · ")}
                        </div>
                      </div>
                      {c.website && (
                        <span className="text-xs text-primary truncate max-w-[140px] hidden sm:inline">{c.website}</span>
                      )}
                    </button>
                  ))}
                  {customers.length >= 200 && (
                    <p className="text-center text-xs text-muted-foreground py-2">
                      İlk 200 gösteriliyor — tümü için "Müşterilerde Aç"
                    </p>
                  )}
                </div>
              )}
            </div>
          </div>
        </div>
      )}
    </div>
  );
}
